`struct Arena { pool: Vec<u8>, pos: usize }
impl Arena {
  fn new(size: usize) -> Self {
    Arena{ pool: vec![0; size], pos: 0 }
  }

  fn alloc(&mut self, data: &[u8]) -> Result<&[u8], &'static str> {
    let start = self.pos;
    if start + data.len() > self.pool.len() {
      return Err("Arena overflow")
    }
    self.pool[start..start+data.len()].copy_from_slice(data);
    self.pos += data.len();

    Ok(&self.pool[start..start+data.len()])
  }
}`

