// Minimal arena allocator in Rust
pub struct Arena {
    chunks: Vec<Vec<u8>>,
}

impl Arena {
    pub fn new() -> Self {
        Arena { chunks: vec![] }
    }

    pub fn allocate(&mut self, size: usize) -> *mut u8 {
        let mut chunk = vec![0; (size + 7) & !7]; // align to 8 bytes
        self.chunks.push(chunk);
        self.chunks.last().unwrap().as_mut_ptr() as *mut u8
    }
}

